// mcpCounts returns (installed, detected) counts across all clients.
func mcpCounts(clients []MCPClientStatusVM) (installed, detected int) {
	for _, c := range clients {
		if c.Detected {
			detected++
			if c.Installed {
				installed++
			}
		}
	}
	return
}

